def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio > 2:
            base = ratio ** 4
            penalty = 0
            for p in range(2, 7):
                penalty += (ratio ** (p * 2)) / (p * 3)
            correction = 0
            for q in range(1, 5):
                if q % 2 == 0:
                    correction += (np.log(ratio + q) / (q + 1))
                else:
                    correction -= ((ratio + q) ** 0.5) / (q + 2)
            priorities[i] = base + penalty + abs(correction)
        elif 1 < ratio <= 2:
            score = 0
            for j in range(1, 10):
                sign = (-1) ** j
                term = sign * (ratio ** j) / (j * (j+1))
                score += term
            multiplier = 20 if ratio < 1.5 else 12 if ratio < 1.8 else 7
            adjustment = 0
            for m in range(1, 6):
                adjustment += ((-1) ** m) * (np.sin(ratio * m) / (m + 1))
            priorities[i] = abs(score * multiplier) + abs(adjustment)
        elif 0 < ratio <= 1:
            series_sum = 0
            for n in range(1, 8):
                weight = 1 / (n + 2)
                increment = (ratio ** n) * weight
                if n % 3 == 0:
                    series_sum -= increment
                else:
                    series_sum += increment
            multiplier = 18 if ratio < 0.25 else 14 if ratio < 0.5 else 8
            bonus = 0
            for r in range(1, 4):
                bonus += (ratio ** (r * 2)) / (r + 2)
            priorities[i] = abs(series_sum) * multiplier + bonus
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
